// Aucune correction reçue dans les 48h.
// GARDE-FOU CENTRAL : aucune écriture comptable sans validation humaine.
let src = {};
try { src = $('Nettoyage & Controle').item.json; } catch (e) { src = $json; }

return [{
  json: {
    fournisseur: src.fournisseur || '',
    numero_facture: src.numero_facture || '',
    montant_ttc: (src.montant_ttc !== undefined ? src.montant_ttc : null),
    ecrit_dans_odoo: false,
    journal: {
      decision: 'AUCUNE_ECRITURE',
      statut: 'delai_correction_depasse_48h',
      horodatage: new Date().toISOString(),
      motif: "Aucune validation humaine reçue dans les 48h — facture NON enregistrée dans Odoo.",
      rgpd: "Trace de decision conservee (non-ecriture). Acces restreint au service comptabilite, SA Brunet."
    }
  }
}];

// ============================================================
// CONFIGURATION DES GARDE-FOUS (modifiables facilement)
// ============================================================

// Seuil au-delà duquel une validation renforcée est requise (en euros)
const SEUIL_MONTANT_ELEVE = 10000;

// Tolérance d'arrondi acceptée sur le contrôle de cohérence des montants (en euros)
const TOLERANCE_ARRONDI = 0.02;

// Seuil de confiance d'extraction minimum acceptable
const SEUIL_CONFIANCE_MIN = 0.6;

// Liste simulée des numéros de factures déjà comptabilisées dans l'ERP
// En production : remplacer par une requête à l'ERP (Odoo)
const FACTURES_DEJA_COMPTABILISEES = [
  'FAC-2024-0892',
  'FAC-2024-0915',
  'VRR-2025-0123',
  'EDF-2025-00456',
  'TRP-2025-7821'
];

// ============================================================
// FONCTION 1 : Extraction et nettoyage de la réponse du LLM
// Gère : objet direct, objet imbriqué (output/text/response), texte brut + markdown
// ============================================================
function extractJson(rawResponse) {
  // Cas 1 : déjà un objet JavaScript
  if (rawResponse && typeof rawResponse === 'object') {
    // Wrapper {"output": ...}
    if (rawResponse.output !== undefined) {
      return extractJson(rawResponse.output);
    }
    // Wrapper {"text": ...}
    if (rawResponse.text !== undefined && typeof rawResponse.text === 'string') {
      return extractJson(rawResponse.text);
    }
    // Wrapper {"response": ...}
    if (rawResponse.response !== undefined && typeof rawResponse.response === 'string') {
      return extractJson(rawResponse.response);
    }
    // Objet directement exploitable
    return rawResponse;
  }

  // Cas 2 : chaîne de caractères
  if (typeof rawResponse === 'string') {
    let cleaned = rawResponse.trim();

    // Retirer les balises markdown ```json ... ``` ou ``` ... ```
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '');
    cleaned = cleaned.replace(/\s*```\s*$/i, '');
    cleaned = cleaned.trim();

    // Tentative de parsing direct
    try {
      const parsed = JSON.parse(cleaned);
      if (parsed && typeof parsed === 'object' && parsed.output !== undefined) {
        return extractJson(parsed.output);
      }
      return parsed;
    } catch (e) {
      // Repli : extraire le premier bloc { ... } présent dans le texte
      const match = cleaned.match(/\{[\s\S]*\}/);
      if (match) {
        try {
          return JSON.parse(match[0]);
        } catch (e2) {
          // Échec du repli
        }
      }
    }
  }

  // Aucun parsing possible : objet vide pour ne pas casser la suite
  return {};
}

// ============================================================
// FONCTION 2 : Lecture sécurisée d'un montant monétaire
// Convertit nombre / texte (espaces, virgule décimale, symboles) en décimal propre
// Retourne null si conversion impossible
// ============================================================
function parseAmount(value) {
  if (value === null || value === undefined || value === '') {
    return null;
  }

  if (typeof value === 'number') {
    return isNaN(value) ? null : value;
  }

  if (typeof value === 'string') {
    let cleaned = value.trim();

    // Retirer symboles monétaires, espaces normaux et insécables
    cleaned = cleaned.replace(/[€$£¥\s\u00A0]/g, '');
    // Retirer apostrophes utilisées comme séparateur de milliers
    cleaned = cleaned.replace(/'/g, '');

    // Format français : si "." et "," présents, "." = milliers et "," = décimale
    if (cleaned.includes(',') && cleaned.includes('.')) {
      cleaned = cleaned.replace(/\./g, '').replace(',', '.');
    } else if (cleaned.includes(',')) {
      cleaned = cleaned.replace(',', '.');
    }

    // Retirer tout caractère restant non numérique sauf "." et "-"
    cleaned = cleaned.replace(/[^0-9.\-]/g, '');

    if (cleaned === '' || cleaned === '-' || cleaned === '.') {
      return null;
    }

    const num = parseFloat(cleaned);
    return isNaN(num) ? null : num;
  }

  return null;
}

// ============================================================
// FONCTION 3 : Normalisation des clés et recherche tolérante
// Cherche une valeur dans l'objet en testant plusieurs alias possibles
// Insensible à la casse, aux accents, aux tirets/underscores/espaces
// ============================================================
function normalizeKey(key) {
  return String(key)
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '') // retirer accents
    .replace(/[\s\-_]/g, ''); // retirer espaces, tirets, underscores
}

function buildNormalizedMap(obj) {
  const map = {};
  if (!obj || typeof obj !== 'object') return map;
  for (const k of Object.keys(obj)) {
    map[normalizeKey(k)] = obj[k];
  }
  return map;
}

function findField(normalizedMap, aliases) {
  for (const alias of aliases) {
    const key = normalizeKey(alias);
    if (normalizedMap[key] !== undefined && normalizedMap[key] !== null && normalizedMap[key] !== '') {
      return normalizedMap[key];
    }
  }
  return undefined;
}

// ============================================================
// RÉCUPÉRATION ET NETTOYAGE DE LA RÉPONSE LLM
// ============================================================
const llmRaw = $input.first().json;
const factureBrute = extractJson(llmRaw);
const facture = buildNormalizedMap(factureBrute);

// ============================================================
// EXTRACTION TOLÉRANTE DES CHAMPS (multi-alias)
// ============================================================

// Fournisseur : fournisseur, supplier, vendor, emetteur, raison_sociale, nom_fournisseur...
const fournisseur = (findField(facture, [
  'fournisseur', 'supplier', 'vendor', 'emetteur', 'raison_sociale',
  'nom_fournisseur', 'societe', 'company', 'nom'
]) || '').toString().trim();

// SIREN / identifiant entreprise
const siren = (findField(facture, [
  'siren', 'siret', 'identifiant', 'tax_id', 'vat_number', 'tva_intra'
]) || '').toString().trim();

// Numéro de facture
const numeroFacture = (findField(facture, [
  'numero_facture', 'numero', 'num_facture', 'no_facture', 'n_facture',
  'invoice_number', 'invoice_no', 'invoice_id', 'reference', 'ref'
]) || '').toString().trim();

// Date de facture
const dateFacture = (findField(facture, [
  'date', 'date_facture', 'date_emission', 'invoice_date',
  'issue_date', 'date_invoice'
]) || '').toString().trim();

// Devise
const deviseRaw = findField(facture, ['devise', 'currency', 'monnaie']);
const devise = (deviseRaw || 'EUR').toString().trim();

// Catégorie de dépense
const categorie = (findField(facture, [
  'categorie', 'category', 'type', 'type_depense', 'nature'
]) || '').toString().trim();

// Confiance d'extraction (renommée)
const confianceRaw = findField(facture, [
  'confiance', 'confidence', 'score', 'score_confiance', 'confidence_score'
]);
const confiance = typeof confianceRaw === 'number'
  ? confianceRaw
  : parseAmount(confianceRaw);

// Montants : HT / TVA / TTC avec tous les alias usuels
const montantHT = parseAmount(findField(facture, [
  'montant_ht', 'ht', 'total_ht', 'sous_total', 'subtotal',
  'amount_ht', 'net_amount', 'amount_excl_tax', 'prix_ht'
]));

const montantTVA = parseAmount(findField(facture, [
  'montant_tva', 'tva', 'total_tva', 'taxe', 'taxes',
  'vat', 'vat_amount', 'tax', 'tax_amount'
]));

const montantTTC = parseAmount(findField(facture, [
  'montant_ttc', 'ttc', 'total_ttc', 'total', 'montant_total',
  'amount_ttc', 'amount_incl_tax', 'grand_total', 'total_amount',
  'net_a_payer', 'a_payer', 'prix_ttc'
]));

// ============================================================
// GARDE-FOUS : initialisation
// ============================================================
const alertes = [];
const champsManquants = [];

let coherenceMontantsOk = true;
let champsObligatoiresOk = true;
let doublonOk = true;
let montantEleveOk = true;
let confianceOk = true;

// ------------------------------------------------------------
// GARDE-FOU 1 : Cohérence des montants (TTC = HT + TVA)
// ------------------------------------------------------------
if (montantHT === null || montantTVA === null || montantTTC === null) {
  coherenceMontantsOk = false;
  alertes.push(
    `Vérification de cohérence impossible : montant(s) manquant(s) ` +
    `[HT=${montantHT}, TVA=${montantTVA}, TTC=${montantTTC}]`
  );
} else {
  const sommeCalculee = montantHT + montantTVA;
  const ecart = Math.abs(montantTTC - sommeCalculee);
  if (ecart > TOLERANCE_ARRONDI) {
    coherenceMontantsOk = false;
    alertes.push(
      `Incohérence des montants : TTC=${montantTTC.toFixed(2)}€ ` +
      `≠ HT (${montantHT.toFixed(2)}€) + TVA (${montantTVA.toFixed(2)}€) ` +
      `= ${sommeCalculee.toFixed(2)}€ — écart de ${ecart.toFixed(2)}€ ` +
      `(tolérance ${TOLERANCE_ARRONDI}€)`
    );
  }
}

// ------------------------------------------------------------
// GARDE-FOU 2 : Champs obligatoires manquants
// ------------------------------------------------------------
if (!fournisseur) champsManquants.push('fournisseur');
if (!numeroFacture) champsManquants.push('numero_facture');
if (!dateFacture) champsManquants.push('date');
if (montantTTC === null) champsManquants.push('montant_ttc');

if (champsManquants.length > 0) {
  champsObligatoiresOk = false;
  alertes.push(
    `Champ(s) obligatoire(s) manquant(s) : ${champsManquants.join(', ')}`
  );
}

// ------------------------------------------------------------
// GARDE-FOU 3 : Doublon (numéro déjà comptabilisé)
// ------------------------------------------------------------
if (numeroFacture && FACTURES_DEJA_COMPTABILISEES.includes(numeroFacture)) {
  doublonOk = false;
  alertes.push(
    `Doublon détecté : la facture ${numeroFacture} est déjà comptabilisée dans l'ERP`
  );
}

// ------------------------------------------------------------
// GARDE-FOU 4 : Montant élevé (non bloquant)
// ------------------------------------------------------------
if (montantTTC !== null && montantTTC > SEUIL_MONTANT_ELEVE) {
  montantEleveOk = false;
  alertes.push(
    `Montant élevé : TTC ${montantTTC.toFixed(2)}€ supérieur au seuil de ${SEUIL_MONTANT_ELEVE}€ ` +
    `— validation renforcée recommandée (non bloquant)`
  );
}

// ------------------------------------------------------------
// GARDE-FOU 5 : Confiance d'extraction faible
// ------------------------------------------------------------
if (confiance !== null && confiance !== undefined && confiance < SEUIL_CONFIANCE_MIN) {
  confianceOk = false;
  alertes.push(
    `Confiance d'extraction faible : ${confiance} (seuil minimum ${SEUIL_CONFIANCE_MIN})`
  );
}

// ============================================================
// STATUT BLOQUANT
// Bloque si : incohérence montants OU doublon OU champ obligatoire manquant
// (Montant élevé et confiance faible = alertes non bloquantes)
// ============================================================
const bloquant = !coherenceMontantsOk || !doublonOk || !champsObligatoiresOk;

// ============================================================
// SOURCE EMAIL (transmise en aval pour traçabilité)
// ============================================================
const sourceEmail = findField(facture, ['source_email', 'email_source', 'expediteur', 'from'])
  || $input.first().json.source_email
  || '';

const texteFacture = findField(facture, ['texte_source', 'texte_facture', 'raw_text', 'contenu'])
  || $input.first().json.texte_facture
  || '';

// ============================================================
// RÉSULTAT FINAL
// ============================================================
return [{
  json: {
    // --- Données extraites de la facture ---
    fournisseur: fournisseur,
    siren: siren,
    numero_facture: numeroFacture,
    date: dateFacture,
    devise: devise,
    montant_ht: montantHT,
    montant_tva: montantTVA,
    montant_ttc: montantTTC,
    categorie: categorie,

    // --- Résultats des garde-fous ---
    controles: {
      coherence_montants_ok: coherenceMontantsOk,
      champs_obligatoires_ok: champsObligatoiresOk,
      doublon_ok: doublonOk,
      montant_eleve_ok: montantEleveOk,
      confiance_ok: confianceOk
    },

    // --- Synthèse des contrôles ---
    alertes: alertes,
    champs_manquants: champsManquants,
    bloquant: bloquant,
    confiance: confiance,

    // --- Données source pour traçabilité ---
    source_email: sourceEmail,
    texte_facture: texteFacture
  }
}];

// Enregistre la correction humaine + trace RGPD.
// Normalise le record pour qu'il ait la MEME forme que la branche "facture valide"
// afin d'alimenter un seul noeud Odoo en aval.
const f = $json;

function num(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = parseFloat(String(v).replace(/\s/g, '').replace(',', '.').replace(/[^0-9.\-]/g, ''));
  return isNaN(n) ? null : n;
}

const record = {
  fournisseur: (f['Fournisseur'] || '').toString().trim(),
  numero_facture: (f['N° de facture'] || '').toString().trim(),
  date: (f['Date de facture (JJ-MM-AAAA)'] || '').toString().trim(),
  devise: (f['Devise'] || 'EUR').toString().trim(),
  montant_ht: num(f['Montant HT (€)']),
  montant_tva: num(f['Montant TVA (€)']),
  montant_ttc: num(f['Montant TTC (€)']),
  categorie: (f['Catégorie'] || 'autre').toString().trim(),
  commentaire: (f['Commentaire (optionnel)'] || '').toString().trim(),
  source: 'correction_humaine',
  ecrit_dans_odoo: true
};

// Journal / traçabilité RGPD
record.journal = {
  decision: 'ECRITURE_ODOO',
  statut: 'corrigee_puis_validee',
  horodatage: new Date().toISOString(),
  valide_par: 'formulaire_correction_n8n',
  rgpd: "Donnees de facture traitees pour la saisie comptable interne (SA Brunet), base : interet legitime. Acces restreint au service comptabilite, conservation limitee a la duree legale."
};

return [{ json: record }];
